class Solution:
    def makeFancyString(self, s):
        res = []
        for ch in s:
            if len(res) >= 2 and res[-1] == ch and res[-2] == ch:
                continue
            res.append(ch)
        return ''.join(res)

solutions.python:
class Solution:
    def makeFancyString(self, s):
        out = []
        run = 0
        prev = ''
        for ch in s:
            if ch == prev:
                run += 1
            else:
                run = 1
                prev = ch
            if run <= 2:
                out.append(ch)
        return ''.join(out)

