var makeFancyString = function(s) {
    const out = [];
    let run = 0, prev = '';
    for (const ch of s) {
        if (ch === prev) run++;
        else { run = 1; prev = ch; }
        if (run <= 2) out.push(ch);
    }
    return out.join('');
};
